Use ASP.NET Core's `WebApplicationFactory<T>` — it hosts your app in-memory and gives you an `HttpClient` that talks to it without a real network listener.

**1. Add the test package**

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test fixture**

```csharp
using Microsoft.AspNetCore.Mvc.Testing;
using System.Net.Http.Json;
using System.Text.Json;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (required by the protocol)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* send initialize + initialized */ }
}
```

**3. Override services if needed**

```csharp
var factory = new WebApplicationFactory<Program>()
    .WithWebHostBuilder(builder =>
    {
        builder.ConfigureServices(services =>
        {
            // Swap real dependencies for fakes
            services.AddSingleton<IMyService, FakeMyService>();
        });
    });
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory test server (`TestServer`).
- **Full pipeline** — middleware, routing, DI, serialization all run exactly as in production.
- **MCP is JSON-RPC over HTTP** — just `POST` JSON-RPC messages and assert on the JSON-RPC responses.
- **Stateful sessions** — if your server uses `Mcp-Session-Id`, capture it from the `initialize` response and attach it to subsequent requests via a header.
- Make sure `Program` is accessible (add `public partial class Program { }` at the bottom of your `Program.cs` if using top-level statements).
